import * as React from "react";
import { FormRenderer, type FormErrors, type FormValues, type RendererFormSpec } from "@flowforge/renderer";
import "@flowforge/renderer/styles.css";

import formSpec from "../../../../workflows/claim_intake/form_spec.json";
import { ANALYTICS_EVENTS, type AnalyticsEvent } from "../../insurance_claim_demo/analytics";
// v0.3.0 W3 / item 18 — design tokens. Side-effect import publishes the
// `--color-primary` / `--font-family` / `--radius-*` CSS variables so the
// inline `style` attribute below picks them up live; a re-run of
// `flowforge jtbd-generate` against a tweaked `project.design` re-themes
// every Step component that imports this file.
import "../../insurance_claim_demo/design_tokens.css";
// v0.3.0 W4b / item 17 — i18n. The generated catalog is keyed by a
// closed string-literal union; field labels below resolve through
// `useT()` so hosts can swap the active locale by wrapping this Step
// with an `I18nContext.Provider` without forking the template.
import { useT } from "../../insurance_claim_demo/i18n/useT";

/**
 * Compatibility-shaped subset of `flowforge.ports.analytics.AnalyticsPort`
 * that the Step component calls. Hosts wiring Segment / Mixpanel /
 * Amplitude / a noop sink need only satisfy this surface — the
 * generated frontend never imports an SDK directly (item 16 of
 * docs/improvements.md, hexagonal port discipline).
 */
export interface AnalyticsTracker {
	track(eventName: AnalyticsEvent, properties: Record<string, unknown>): void | Promise<void>;
}

export interface PiiRevealDetail {
	instanceId: string;
	jtbdId: "claim_intake";
	fieldId: string;
	reason: string;
}

export interface ClaimIntakeStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
	/** Optional context map for show_if conditional fields (reuses the engine's `var` operator). */
	context?: Record<string, unknown>;
	/** Optional analytics sink; closed-taxonomy events fire through here when provided. */
	analytics?: AnalyticsTracker;
	/** Explicitly exposes workflow state / instance diagnostics for developer tools. */
	developerMode?: boolean;
	/** Optional audit hook; PII is revealed only after this hook succeeds. */
	onPiiReveal?: (detail: PiiRevealDetail) => void | Promise<void>;
}

interface FieldMeta {
	id: string;
	label: string;
	required: boolean;
	pii: boolean;
}

const FIELDS: ReadonlyArray<FieldMeta> = [
	{ id: "claimant_name", label: "Claimant full name", required: true, pii: true },
	{ id: "policy_number", label: "Policy number", required: true, pii: false },
	{ id: "loss_date", label: "Date of loss", required: true, pii: false },
	{ id: "loss_amount", label: "Estimated loss amount", required: true, pii: false },
	{ id: "loss_description", label: "Description of loss", required: true, pii: false },
	{ id: "contact_email", label: "Contact email", required: true, pii: true },
	{ id: "contact_phone", label: "Contact phone", required: false, pii: true },
];

const SPEC = formSpec as unknown as RendererFormSpec;
const PII_FIELD_IDS: ReadonlyArray<string> = FIELDS.filter((f) => f.pii).map((f) => f.id);

// Lifecycle event names — closed against the bundle's taxonomy in
// `insurance_claim_demo/analytics.ts`. Inlining the constants here
// keeps the Step's analytics surface explicit at a glance and gives
// the TS compiler a closed set to type-check against.
const EVT_FIELD_FOCUSED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_FIELD_FOCUSED;
const EVT_FIELD_COMPLETED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_FIELD_COMPLETED;
const EVT_PII_REVEALED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_PII_REVEALED;
const EVT_VALIDATION_FAILED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_VALIDATION_FAILED;
const EVT_SUBMISSION_STARTED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_SUBMISSION_STARTED;
const EVT_SUBMISSION_SUCCEEDED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_SUBMISSION_SUCCEEDED;
const EVT_FORM_ABANDONED: AnalyticsEvent = ANALYTICS_EVENTS.CLAIM_INTAKE_FORM_ABANDONED;

/**
 * Real form step for the claim_intake workflow. Wraps `@flowforge/renderer`'s
 * FormRenderer over the generated form_spec.json. Validators are derived from
 * data_capture.validation; show_if uses the engine's whitelisted `var` operator
 * (no new operators introduced).
 *
 * PII fields default to a masked text node with a reason-gated icon button,
 * keeping screen leaks to a minimum during shoulder-surfing demos. Inline
 * errors link via `aria-describedby` so assistive tech surfaces them next to
 * the offending field.
 *
 * Analytics: the Step fires the closed taxonomy events from
 * `insurance_claim_demo/analytics.ts` through an optional `analytics` prop
 * (item 16 of docs/improvements.md). When the prop is omitted, no events
 * fire — the analytics surface is pure observability.
 */
export function ClaimIntakeStep(props: ClaimIntakeStepProps): React.ReactElement {
	const t = useT();
	const [busy, setBusy] = React.useState(false);
	const [values, setValues] = React.useState<FormValues>({});
	const [errors, setErrors] = React.useState<FormErrors>({});
	const [revealedPii, setRevealedPii] = React.useState<ReadonlyArray<string>>([]);
	const [piiRevealReasons, setPiiRevealReasons] = React.useState<Record<string, string>>({});
	const [piiRevealErrors, setPiiRevealErrors] = React.useState<Record<string, string>>({});
	const [pendingPiiReveal, setPendingPiiReveal] = React.useState<ReadonlyArray<string>>([]);

	// Analytics bookkeeping. Refs avoid useEffect re-runs and keep the
	// `emit` closure stable across renders.
	const analyticsRef = React.useRef<AnalyticsTracker | undefined>(props.analytics);
	analyticsRef.current = props.analytics;
	const valuesRef = React.useRef<FormValues>(values);
	valuesRef.current = values;
	const focusedRef = React.useRef<Set<string>>(new Set());
	const completedRef = React.useRef<Set<string>>(new Set());
	const submittedRef = React.useRef(false);
	const instanceIdRef = React.useRef(props.instanceId);
	instanceIdRef.current = props.instanceId;

	const emit = React.useCallback(
		(eventName: AnalyticsEvent, properties: Record<string, unknown>) => {
			const sink = analyticsRef.current;
			if (sink == null) return;
			const enriched = { instanceId: instanceIdRef.current, jtbdId: "claim_intake", ...properties };
			try {
				const result = sink.track(eventName, enriched);
				if (result != null && typeof (result as Promise<void>).then === "function") {
					void (result as Promise<void>).catch(() => {
						/* analytics MUST NOT block the user; swallow transport errors. */
					});
				}
			} catch {
				/* synchronous tracker error — swallow for the same reason. */
			}
		},
		[],
	);

	const updatePiiRevealReason = React.useCallback((id: string, reason: string) => {
		setPiiRevealReasons((prev) => ({ ...prev, [id]: reason }));
	}, []);

	const togglePii = React.useCallback(
		async (id: string) => {
			if (revealedPii.includes(id)) {
				setRevealedPii((prev) => prev.filter((x) => x !== id));
				return;
			}

			const reason = (piiRevealReasons[id] ?? "").trim();
			if (reason.length === 0 || pendingPiiReveal.includes(id)) return;

			setPendingPiiReveal((prev) => (prev.includes(id) ? prev : [...prev, id]));
			setPiiRevealErrors((prev) => ({ ...prev, [id]: "" }));
			try {
				await props.onPiiReveal?.({
					instanceId: props.instanceId,
					jtbdId: "claim_intake",
					fieldId: id,
					reason,
				});
				setRevealedPii((prev) => (prev.includes(id) ? prev : [...prev, id]));
				emit(EVT_PII_REVEALED, { fieldId: id, reasonLength: reason.length });
			} catch {
				setPiiRevealErrors((prev) => ({ ...prev, [id]: "Reveal audit failed" }));
			} finally {
				setPendingPiiReveal((prev) => prev.filter((x) => x !== id));
			}
		},
		[emit, pendingPiiReveal, piiRevealReasons, props, revealedPii],
	);

	const fire = React.useCallback(
		async (event: string, payload: Record<string, unknown>) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, { instance_id: props.instanceId, ...payload });
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	const handleChange = React.useCallback(
		(next: FormValues) => {
			const prev = valuesRef.current;
			for (const id of Object.keys(next)) {
				const before = prev[id];
				const after = next[id];
				const wasEmpty = before == null || before === "";
				const isFilled = after != null && after !== "";
				if (wasEmpty && isFilled && !completedRef.current.has(id)) {
					completedRef.current.add(id);
					emit(EVT_FIELD_COMPLETED, { fieldId: id });
				}
			}
			setValues(next);
		},
		[emit],
	);

	const handleValidate = React.useCallback(
		(errs: FormErrors) => {
			setErrors(errs);
			const failedIds = Object.keys(errs).filter((k) => Boolean(errs[k]));
			if (failedIds.length > 0) {
				emit(EVT_VALIDATION_FAILED, { fieldIds: failedIds });
			}
		},
		[emit],
	);

	const handleSubmit = React.useCallback(
		async (submitted: FormValues) => {
			emit(EVT_SUBMISSION_STARTED, { fieldCount: Object.keys(submitted).length });
			await fire("submit", submitted);
			submittedRef.current = true;
			emit(EVT_SUBMISSION_SUCCEEDED, { fieldCount: Object.keys(submitted).length });
		},
		[emit, fire],
	);

	const handleFocusCapture = React.useCallback(
		(ev: React.FocusEvent<HTMLElement>) => {
			const target = ev.target as HTMLElement;
			const fieldId = target.getAttribute("name") ?? target.getAttribute("data-field-id");
			if (fieldId == null) return;
			if (focusedRef.current.has(fieldId)) return;
			focusedRef.current.add(fieldId);
			emit(EVT_FIELD_FOCUSED, { fieldId });
		},
		[emit],
	);

	// Emit `form_abandoned` if the component unmounts before a successful submit.
	React.useEffect(() => {
		return () => {
			if (!submittedRef.current) {
				emit(EVT_FORM_ABANDONED, {
					focusedCount: focusedRef.current.size,
					completedCount: completedRef.current.size,
				});
			}
		};
	}, [emit]);

	return (
		<section
			data-flowforge-form-root
			data-testid="claim_intake-step"
			aria-labelledby="claim_intake-step-title"
			onFocusCapture={handleFocusCapture}
			style={{ fontFamily: "var(--font-family)", borderRadius: "var(--radius-md)", padding: "var(--density-padding)" }}		>
			<header>
				<h2 id="claim_intake-step-title" style={{ color: "var(--color-primary)" }}>{t("jtbd.claim_intake.title")}</h2>
				{props.developerMode ? (
					<dl aria-label="Workflow diagnostics">
						<dt>State</dt>
						<dd><code>{props.state}</code></dd>
						<dt>Instance</dt>
						<dd><code>{props.instanceId}</code></dd>
					</dl>
				) : null}
			</header>
			<FormRenderer
				spec={SPEC}
				values={values}
				onChange={handleChange}
				onSubmit={handleSubmit}
				onValidate={handleValidate}
				validateOn="blur"
				disabled={busy}
				submitLabel={busy ? "Submitting…" : t("jtbd.claim_intake.button.submit")}
				data-testid="claim_intake-form"
			/>
			{PII_FIELD_IDS.length > 0 ? (
				<aside aria-label="PII fields">
					<h3>Sensitive fields</h3>
					<ul>
						{PII_FIELD_IDS.map((id) => {
							const revealed = revealedPii.includes(id);
							const raw = values[id];
							const display = revealed ? (raw == null ? "" : String(raw)) : "••••••";
							const errorId = errors[id] ? `${id}-error` : undefined;
							const revealError = piiRevealErrors[id];
							const revealErrorId = revealError ? `${id}-pii-reveal-error` : undefined;
							const describedBy = [errorId, revealErrorId].filter((v): v is string => v != null).join(" ") || undefined;
							const labelKey = `jtbd.claim_intake.field.${id}.label` as const;
							const fieldLabel = t(labelKey as Parameters<typeof t>[0]);
							const revealReason = piiRevealReasons[id] ?? "";
							const revealPending = pendingPiiReveal.includes(id);
							const canReveal = revealed || revealReason.trim().length > 0;
							const revealTitle = revealed
								? `Hide ${fieldLabel}`
								: canReveal
									? `Reveal ${fieldLabel}`
									: `Enter a reason before revealing ${fieldLabel}`;
							return (
								<li key={id}>
									<span>{fieldLabel}: </span>
									<span aria-describedby={describedBy} data-pii-revealed={revealed ? "true" : "false"}>
										{display}
									</span>
									<input
										type="text"
										value={revealReason}
										onChange={(ev) => updatePiiRevealReason(id, ev.currentTarget.value)}
										aria-label={`Reason for revealing ${fieldLabel}`}
										autoComplete="off"
										disabled={revealed || revealPending}
									/>
									<button
										type="button"
										onClick={() => void togglePii(id)}
										aria-label={revealTitle}
										title={revealTitle}
										aria-pressed={revealed}
										disabled={revealPending || !canReveal}
									>
										<PiiRevealIcon revealed={revealed} />
									</button>
									{errorId ? (
										<span id={errorId} role="alert">
											{errors[id]}
										</span>
									) : null}
									{revealErrorId ? (
										<span id={revealErrorId} role="alert">
											{revealError}
										</span>
									) : null}
								</li>
							);
						})}
					</ul>
				</aside>
			) : null}
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("approve", {})}>
					{t("jtbd.claim_intake.button.approve")}
				</button>
			</footer>
		</section>
	);
}

function PiiRevealIcon({ revealed }: { revealed: boolean }): React.ReactElement {
	return revealed ? (
		<svg aria-hidden="true" focusable="false" width="16" height="16" viewBox="0 0 16 16">
			<path d="M2 2l12 12" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" />
			<path
				d="M1.5 8s2.4-4 6.5-4 6.5 4 6.5 4-2.4 4-6.5 4-6.5-4-6.5-4z"
				fill="none"
				stroke="currentColor"
				strokeWidth="1.4"
			/>
		</svg>
	) : (
		<svg aria-hidden="true" focusable="false" width="16" height="16" viewBox="0 0 16 16">
			<path
				d="M1.5 8s2.4-4 6.5-4 6.5 4 6.5 4-2.4 4-6.5 4-6.5-4-6.5-4z"
				fill="none"
				stroke="currentColor"
				strokeWidth="1.4"
			/>
			<circle cx="8" cy="8" r="2" fill="currentColor" />
		</svg>
	);
}
